#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll unsigned long long
const int N=24000005;
ll n,m,tr[N],tab[N],cnt=1,L[N],R[N];
void push_down(ll u,ll l,ll r)
{
	ll ls=L[u],rs=R[u],mid=(l+r)>>1;
	if(ls==0) ls=L[u]=++cnt;
	if(rs==0) rs=R[u]=++cnt;
	tr[ls]+=(tab[u]*(mid-l+1));
	tab[ls]+=tab[u];
	tr[rs]+=(tab[u]*(r-mid));
	tab[rs]+=tab[u];
	tab[u]=0;
}
void update(ll u,ll l,ll r,ll x,ll y,ll k)
{
	if(l>y||r<x) return ;
	if(l>=x&&r<=y)
	{
		tr[u]+=(k*(r-l+1));
		tab[u]+=k;
		return ;
	}
	ll mid=(l+r)>>1;
	push_down(u,l,r);
	int ls=L[u],rs=R[u];
	if(ls==0) ls=L[u]=++cnt;
	if(rs==0) rs=R[u]=++cnt;
	update(ls,l,mid,x,y,k);
	update(rs,mid+1,r,x,y,k);
	tr[u]=tr[ls]+tr[rs];
}
ll query(ll u,ll l,ll r,ll x,ll y)
{
	if(l>y||r<x) return 0;
	if(l>=x&&r<=y) return tr[u];
	push_down(u,l,r);
	ll mid=(l+r)>>1;
	int ls=L[u],rs=R[u];
	if(ls==0) ls=L[u]=++cnt;
	if(rs==0) rs=R[u]=++cnt;
	return query(ls,l,mid,x,y)+query(rs,mid+1,r,x,y);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	while(m--)
	{
		ll op;
		cin>>op;
		if(op==1)
		{
			ll x,y,k;
			cin>>x>>y>>k;
			update(1,1,n,x,y,k);
		}
		else
		{
			ll x,y;
			cin>>x>>y;
			cout<<(x+y)*(y-x+1)/2+query(1,1,n,x,y)<<'\n';
		}
	}
	return 0;
}
